import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"The Rundown AI — 2026-04-23","description":"","frontmatter":{"title":"The Rundown AI — 2026-04-23","date":"2026-04-23T00:00:00.000Z","source":"The Rundown AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-23-the-rundown-ai.md","filePath":"research/ai-news/2026-04/2026-04-23-the-rundown-ai.md","lastUpdated":1779898012000}'),n={name:"research/ai-news/2026-04/2026-04-23-the-rundown-ai.md"};function s(i,e,p,m,u,d){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="🗞️-the-rundown-ai-—-2026-04-23" tabindex="-1">🗞️ The Rundown AI — 2026-04-23 <a class="header-anchor" href="#🗞️-the-rundown-ai-—-2026-04-23" aria-label="Permalink to &quot;🗞️ The Rundown AI — 2026-04-23&quot;">​</a></h1><blockquote><p>每日 AI 產業動態，通俗易懂、密度高 來源：<a href="https://rss.beehiiv.com/feeds/2R3C6Bt5wj.xml" target="_blank" rel="noreferrer">The Rundown AI</a></p></blockquote><hr><h2 id="anthropic-s-locked-down-mythos-leaks" tabindex="-1"><a href="https://www.therundown.ai/p/anthropic-locked-down-mythos-leaks" target="_blank" rel="noreferrer">Anthropic&#39;s locked-down Mythos leaks</a> <a class="header-anchor" href="#anthropic-s-locked-down-mythos-leaks" aria-label="Permalink to &quot;[Anthropic&#39;s locked-down Mythos leaks](https://www.therundown.ai/p/anthropic-locked-down-mythos-leaks)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-04-23</em></p><p><a href="./">Read Online</a> | <a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">Sign Up</a> | <a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">Advertise</a></p><p><a href="https://app.bland.ai/login?utm_source=AI_Rundown&amp;utm_medium=email&amp;utm_campaign=norm&amp;utm_content=apr23_2026" target="_blank" rel="noreferrer"></a></p><p>Good morning, AI enthusiasts. Anthropic said Mythos was too dangerous to release to the public. Weeks later, a Discord group is reportedly using it daily.</p><p>Working off naming conventions leaked in a data breach and a borrowed contractor login, the group slipped into Anthropic&#39;s most restricted AI to date — a bad start for keeping increasingly powerful systems under wraps.</p><p>In today’s AI rundown:</p><p>Anthropic&#39;s locked-down Mythos leaked</p><p>SpaceX stakes $60B on AI coding startup Cursor</p><p>Use this dictation strategy to write better docs</p><p>ChatGPT’s Codex-powered agents for teams</p><p>4 new AI tools, community workflows, and more</p><p>LATEST DEVELOPMENTS</p><p>ANTHROPIC</p><p>🔓 <a href="https://www.bloomberg.com/news/articles/2026-04-21/anthropic-s-mythos-model-is-being-accessed-by-unauthorized-users?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">Anthropic&#39;s locked-down Mythos leaked</a></p><p>Image source: Images 2.0 / The Rundown</p><p>The Rundown: Access to Anthropic&#39;s Mythos model reportedly <a href="https://www.bloomberg.com/news/articles/2026-04-21/anthropic-s-mythos-model-is-being-accessed-by-unauthorized-users?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">leaked</a> into a Discord group within days of launch, after the users reportedly guessed the company’s deployment URL and naming using patterns leaked in the recent Mercor breach.</p><p>The details:</p><p>The cybersecurity model was <a href="https://www.rundown.ai/articles/anthropic-new-ai-is-too-powerful-for-the-world?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">released</a> on April 10 to select partners under ‘Project Glasswing’, with Anthropic deeming it too powerful for public release.</p><p>Bloomberg reported that a private Discord group tracking unreleased models accessed Mythos on release day and has been using it regularly.</p><p>One member had vendor credentials through contract work, with leaked Mercor details helping the group locate and access Mythos online.</p><p>The group told Bloomberg that they do not use Mythos for cyberattacks or other malicious activities, and also claimed access to other unreleased models.</p><p>Why it matters: The first alleged unauthorized use of the AI model that had the White House and others calling emergency meetings didn&#39;t come from China, Russia, or another rival nation — it came from a random Discord group. Not a great start, and the problem only compounds as partner access grows and the models get more dangerous.</p><p>TOGETHER WITH BLAND</p><p>🗣️ <a href="https://app.bland.ai/login?utm_source=AI_Rundown&amp;utm_medium=email&amp;utm_campaign=norm&amp;utm_content=apr23_2026" target="_blank" rel="noreferrer">Build voice agents from a single prompt</a></p><p><a href="https://app.bland.ai/login?utm_source=AI_Rundown&amp;utm_medium=email&amp;utm_campaign=norm&amp;utm_content=apr23_2026" target="_blank" rel="noreferrer"></a></p><p>The Rundown: Meet Norm — Bland AI&#39;s new assistant that builds production-ready voice agents automatically. Just describe what you want the agent to do, and Norm handles the pathways, logic, and setup for you.</p><p>With Norm, you can:</p><p>Spin up voice agents for appointment scheduling, customer support, or lead qualification</p><p>Build safely in an isolated branch without touching your live production agents</p><p>Run agent-on-agent simulations to test performance before going live</p><p><a href="https://app.bland.ai/login?utm_source=AI_Rundown&amp;utm_medium=email&amp;utm_campaign=norm&amp;utm_content=apr23_2026" target="_blank" rel="noreferrer">Try Norm free today</a>.</p><p>SPACEX &amp; CURSOR</p><p>🚀 <a href="https://x.com/SpaceX/status/2046713419978453374?s=20a&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">SpaceX stakes $60B on AI coding startup Cursor</a></p><p>Image source: Cursor</p><p>The Rundown: SpaceX just <a href="https://x.com/SpaceX/status/2046713419978453374?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">announced</a> a new partnership with coding startup Cursor and locked in an option to acquire the company for $60B later this year, handing Elon Musk a shortcut into a race xAI has spent the year losing to Anthropic and OpenAI.</p><p>The details:</p><p>CEO Michael Truell <a href="https://cursor.com/blog/spacex-model-training?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">said</a> each release of Cursor’s Composer models ran into a compute ceiling, with SpaceX&#39;s Colossus now providing the needed power.</p><p>Cursor is guaranteed $10B for the partnership, no matter what, with the full $60B acquisition only happening if Musk exercises it before year-end.</p><p>xAI <a href="https://www.theinformation.com/articles/xai-hires-two-senior-leaders-cursor-catch-coding?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">poached</a> Cursor leads Andrew Milich and Jason Ginsberg last month, with Musk saying the startup “was not built right the first time around”.</p><p>Cursor was <a href="https://www.cnbc.com/2026/04/19/cursor-ai-2-billion-funding-round.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">set to raise</a> $2B at a $50B valuation before the deal, with SpaceX <a href="https://www.bloomberg.com/news/articles/2026-04-21/spacex-says-has-agreement-to-acquire-cursor-for-60-billion?srnd=phx-technology&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">holding off</a> on the acquisition due to complications with the IPO process.</p><p>Why it matters: Musk has tried and failed so far to build a frontier coding tool inside xAI, with Grok having no answer to Claude Code or Codex. This deal swaps in-house build for outside product to level up quickly, and gives Cursor the ability to potentially shift into a SpaceX-fueled coding lab instead of a compute-starved startup.</p><p>AI TRAINING</p><p>✍️ <a href="https://app.therundown.ai/guides/use-this-two-step-dictation-strategy-to-write-better-docs-typeless-tutorial?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">Use this dictation strategy to write better docs</a></p><p><a href="https://app.therundown.ai/guides/use-this-two-step-dictation-strategy-to-write-better-docs-typeless-tutorial?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer"></a></p><p>The Rundown: In this guide, you will learn a two-step voice dictation system that immediately makes you write better and even improves itself over time.</p><p>Step-by-step:</p><p>Install <a href="https://www.typeless.com/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">Typeless</a> for dictation, open a Codex/Claude Code session, and dictate: “Draft an outline for a short internal memo about [topic]”</p><p>Here&#39;s the key part. Tell the agent: “Save this as the initial draft and do not edit it. Now create a separate working draft that we can revise”</p><p>Read it and use Typeless to add comments, pointing out inaccurate things, then things that are missing, and finally phrases that sound generic or too AI</p><p>Prompt: “Rewrite the draft using the comments I left. Write it in my tone. Use my verbiage. No em dashes. Preserve the core points, but cut anything that sounds generic.” Review the rewrite and do one more pass and edit if needed</p><p>Pro tip: Have an agent compare the untouched initial draft against the final drafts every week. It will extract the edits you make and update editorial rules for the future.</p><p>PRESENTED BY BRAINTRUST</p><p>📖 <a href="https://www.braintrust.dev/foundations?utm_source=newsletter&amp;utm_medium=rundown&amp;utm_campaign=evals_course&amp;utm_content=secondary_2026-04-23" target="_blank" rel="noreferrer">The playbook to shipping AI users trust</a></p><p><a href="https://www.braintrust.dev/foundations?utm_source=newsletter&amp;utm_medium=rundown&amp;utm_campaign=evals_course&amp;utm_content=secondary_2026-04-23" target="_blank" rel="noreferrer"></a></p><p>The Rundown: Most teams are shipping AI apps by vibes. Braintrust&#39;s free evals course fixes that by walking you through everything from writing your first eval to scoring multi-step agents in production.</p><p>In this course, you’ll learn:</p><p>How to use LLMs to automatically score outputs</p><p>Building test cases from real production failures</p><p>Analyzing agent workflows to spot failure patterns</p><p><a href="https://www.braintrust.dev/foundations?utm_source=newsletter&amp;utm_medium=rundown&amp;utm_campaign=evals_course&amp;utm_content=secondary_2026-04-23" target="_blank" rel="noreferrer">Start the free course</a>.</p><p>OPENAI</p><p>💼 <a href="https://openai.com/index/introducing-workspace-agents-in-chatgpt/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">ChatGPT’s Codex-powered agents for </a><a href="https://openai.com/index/introducing-workspace-agents-in-chatgpt/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">teams</a></p><p>Image source: OpenAI</p><p>The Rundown: OpenAI just <a href="https://openai.com/index/introducing-workspace-agents-in-chatgpt/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">introduced</a> Workspace Agents in ChatGPT, new Codex-powered shared bots designed to tackle multi-step team workflows autonomously across ChatGPT and Slack.</p><p>The details:</p><p>Workspace agents are pitched as an &#39;evolution&#39; of 2023&#39;s solo-user GPTs, with old GPTs still working for now and a conversion tool coming soon.</p><p>Backed by Codex in the cloud, agents can retain memory, call connected apps, and live in Slack or trigger on a schedule when users are offline.</p><p>Inside OAI, sales reps use the feature for account research and follow-up drafts, while accounting runs it for journal entries and reconciliations.</p><p>Custom agents can be created via ChatGPT and shared across teams, with the ability to set restrictions on data usage, approvals, and permissions.</p><p>Why it matters: OAI&#39;s enterprise push is no secret, and workspace agents solve a real problem — every team has accumulated scattered prompts and half-built workflows over the last two years, and few have unified them. The initial GPT Store didn&#39;t stick, but agentic upgrades and an enterprise shift could help this debut find a better fit.</p><p>QUICK HITS</p><p>🛠️ <a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">Trending AI Tools</a></p><p>🎆 <a href="https://www.rundown.ai/tools/chatgpt-images-2-0?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">ChatGPT Images 2.0</a> - OpenAI’s new next-generation image model</p><p>🤖 <a href="http://www.rundown.ai/tools/gemini-enterprise-agent-platform?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">Gemini Enterprise Agent Platform</a> - Build, scale, govern enterprise agents</p><p>🤖 <a href="https://www.rundown.ai/tools/workspace-agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">Workspace Agents</a> - OpenAI&#39;s Codex-powered team agents</p><p>🎨 <a href="https://www.rundown.ai/tools/ideogram-custom-models?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">Ideogram Custom Models</a> - Train image models from your own assets</p><p>📰 <a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">Everything else in AI today</a></p><p>Anthropic <a href="https://x.com/TheAmolAvasare/status/2046724659039932830?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">faced</a> backlash after Claude Code was removed for some new users on the Pro tier, with the company saying it was running a “small test” on the signup flow.</p><p>Google <a href="https://blog.google/innovation-and-ai/infrastructure-and-cloud/google-cloud/eighth-generation-tpu-agentic-era/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">unveiled</a> its new 8th-generation TPUs built for agent workloads, separating training and inference into two separate chips for the first time.</p><p>Ideogram <a href="https://x.com/ideogram_ai/status/2046993830952771724?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">launched</a> Custom Models, letting users fine-tune image generation on 15-100 of their own assets for consistent on-brand outputs.</p><p>Google <a href="https://blog.google/innovation-and-ai/infrastructure-and-cloud/google-cloud/cloud-next-2026-sundar-pichai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">revealed</a> 75% of its in-house code is now AI-generated, with the company seeing major gains in security and operations through AI and agentic implementations.</p><p>Odyssey <a href="https://odyssey.ml/introducing-odyssey-2-max?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">introduced</a> Odyssey-2 Max, a 3x-larger world model that topped physics benchmark scores in real time and is now in private beta.</p><p>Alibaba&#39;s Qwen team <a href="https://qwen.ai/blog?id=qwen3.6-27b&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">open-sourced</a> Qwen3.6-27B, a 27B model that surpassed its own 397B predecessor across top coding benchmarks.</p><p>COMMUNITY</p><p>🤝 <a href="https://docs.google.com/forms/d/e/1FAIpQLSfH4UPzu72HTpdb08Qlm-0dLwKJIjdcAwCcAvVywcHD6mwKig/viewform?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">Community AI workflows</a></p><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader Brigid H. in New Zealand:</p><p>“I created a full app for our farm business in Claude to record and track all stock purchases, sales, deaths &amp; health treatments. It has a full section for all invoices and any other files and attachments. This will keep track of any stock purchases and treatments such as shearing and drenching. It has been a game-changer!”</p><p>How do you use AI? Tell us <a href="https://docs.google.com/forms/d/e/1FAIpQLSfH4UPzu72HTpdb08Qlm-0dLwKJIjdcAwCcAvVywcHD6mwKig/viewform?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">here</a>.</p><p>🎓 <a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">Highlights: News, Guides &amp; Events</a></p><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/openai-reclaims-the-image-crown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">OpenAI reclaims the image crown</a></p><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/apple-gets-a-new-boss?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">Apple gets a new boss</a></p><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/humanoid-smokes-half-marathon-record?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">Humanoid smokes half-marathon record</a></p><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/use-this-two-step-dictation-strategy-to-write-better-docs-typeless-tutorial?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">Write better docs</a><a href="https://app.therundown.ai/guides/use-this-two-step-dictation-strategy-to-write-better-docs-typeless-tutorial?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer"> using dictation</a></p><p>RSVP to workshop April 30 @ 2PM EST: <a href="https://app.therundown.ai/calendar-events/69e77469e7e908f6d4ebdf72?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=anthropic-s-locked-down-mythos-leaks" target="_blank" rel="noreferrer">Codex for non-technical operators</a></p><p>See you soon,</p><p>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</p><hr>',102)])])}const h=t(n,[["render",s]]);export{c as __pageData,h as default};
